function CallbackPage() {
  const { exchangeCodeForTokens, fetchUserInfo, error: authError } = useAuth();
  const { navigate } = useRouter();
  const [error, setError] = useState(null);
  const [processing, setProcessing] = useState(true);

  useEffect(() => {
    const handleCallback = async () => {
      try {
        const urlParams = new URLSearchParams(window.location.search);
        const code = urlParams.get('code');
        const state = urlParams.get('state');
        const errorParam = urlParams.get('error');
        const errorDescription = urlParams.get('error_description');

        if (errorParam) {
          throw new Error(errorDescription || errorParam);
        }

        if (!code) {
          throw new Error('No authorization code received.');
        }

        await exchangeCodeForTokens(code, state);
        await fetchUserInfo();

        // Clean URL and redirect
        navigate('/dashboard');
      } catch (err) {
        console.error('Callback error:', err);
        setError(err.message);
        setProcessing(false);
      }
    };

    handleCallback();
  }, [exchangeCodeForTokens, fetchUserInfo, navigate]);

  if (error || authError) {
    return React.createElement(
      'div',
      { style: styles.app },
      React.createElement(
        'div',
        { style: { ...styles.card, textAlign: 'center', marginTop: '40px' } },
        React.createElement('div', { style: { fontSize: '48px', marginBottom: '16px' } }, '❌'),
        React.createElement('h2', null, 'Authentication Failed'),
        React.createElement('div', { style: styles.error }, error || authError),
        React.createElement(
          'button',
          {
            style: styles.button,
            onClick: () => navigate('/'),
          },
          'Back to Login'
        )
      )
    );
  }

  if (processing) {
    return React.createElement(LoadingSpinner, { message: 'Completing sign in...' });
  }

  return null;
}

